import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Platform {
  FACEBOOK = 'Facebook',
  TIKTOK = 'TikTok',
  INSTAGRAM = 'Instagram',
  YOUTUBE = 'YouTube'
}

export enum ServiceType {
  FOLLOWERS = 'Followers',
  LIKES = 'Likes',
  VIEWS = 'Views',
  COMMENTS = 'Comments'
}

export enum OrderStatus {
  PENDING = 'Pending',
  PROCESSING = 'Processing',
  COMPLETED = 'Completed',
  PARTIAL = 'Partial',
  REFUNDED = 'Refunded'
}

export interface User {
  id: string;
  username: string;
  email: string;
  role: 'user' | 'admin';
  balance: number;
  apiKey: string;
  referralCode: string;
  createdAt: string;
}

export interface Order {
  id: string;
  userId: string;
  platform: Platform;
  service: ServiceType;
  link: string;
  quantity: number;
  price: number;
  status: OrderStatus;
  createdAt: string;
  progress: number; // 0-100
}

export interface Transaction {
  id: string;
  userId: string;
  amount: number;
  status: 'pending' | 'approved' | 'rejected';
  proofUrl?: string;
  createdAt: string;
}

export interface Ticket {
  id: string;
  userId: string;
  subject: string;
  category: string;
  status: 'Open' | 'Resolved';
  messages: {
    sender: 'user' | 'admin';
    content: string;
    timestamp: string;
  }[];
  createdAt: string;
}

import React, { useState, useEffect, useCallback, createContext, useContext } from 'react';
import { HashRouter as Router, Routes, Route, Navigate, Link, useLocation, useNavigate } from 'react-router-dom';
import { 
  User, Order, OrderStatus, Platform, ServiceType, Transaction, Ticket 
} from './types';
import { COLORS, PLATFORM_LOGOS, PRICING } from './constants';
