  HomeIcon, ShoppingCartIcon, HistoryIcon, WalletIcon, 
  ChatBubbleLeftRightIcon, BeakerIcon, UserGroupIcon, UserCircleIcon, 
  ArrowRightOnRectangleIcon, Bars3Icon, XMarkIcon, SunIcon, MoonIcon,
  ShieldCheckIcon, ChartBarIcon, ComputerDesktopIcon, AdjustmentsHorizontalIcon,
  CheckBadgeIcon, BanknotesIcon
} from '@heroicons/react/24/outline';

// --- Context & State ---

interface AppContextType {
  user: User | null;
  setUser: (user: User | null) => void;
  orders: Order[];
  setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  balance: number;
  setBalance: (amount: number) => void;
  darkMode: boolean;
  setDarkMode: (dark: boolean) => void;
  isSidebarOpen: boolean;
  setIsSidebarOpen: (open: boolean) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

// --- Dummy Data ---

