  { id: '1', platform: Platform.FACEBOOK, type: ServiceType.FOLLOWERS, name: 'Facebook Real Followers', pricePer1000: 1100 },
  { id: '2', platform: Platform.INSTAGRAM, type: ServiceType.LIKES, name: 'Instagram Fast Likes', pricePer1000: 200 },
  { id: '3', platform: Platform.TIKTOK, type: ServiceType.VIEWS, name: 'TikTok Instant Views', pricePer1000: 80 },
  { id: '4', platform: Platform.YOUTUBE, type: ServiceType.COMMENTS, name: 'YouTube Custom Comments', pricePer1000: 1100 },
];

