    { name: 'Manage Orders', path: '/admin/orders', icon: AdjustmentsHorizontalIcon },
    { name: 'Manage Payments', path: '/admin/payments', icon: BanknotesIcon },
    { name: 'Users', path: '/admin/users', icon: UserGroupIcon },
