            <Link to="/support" className="flex items-center justify-center gap-2 w-full py-3 bg-gray-900 dark:bg-gray-800 text-white rounded-xl font-bold hover:bg-gray-800 transition-colors">
              <ChatBubbleLeftRightIcon className="w-5 h-5" />
