const NewOrderPage = () => {
  const { balance, setBalance, setOrders } = useApp();
  const navigate = useNavigate();
  const [platform, setPlatform] = useState<Platform>(Platform.INSTAGRAM);
  const [service, setService] = useState<ServiceType>(ServiceType.FOLLOWERS);
  const [quantity, setQuantity] = useState(100);
  const [link, setLink] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  const price = Math.round(quantity * PRICING[service]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (balance < price) {
      alert("Insufficient balance. Please fund your wallet.");
      return;
    }

    setIsProcessing(true);
    setTimeout(() => {
      const newOrder: Order = {
        id: 'ORD-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
        userId: 'current',
        platform,
        service,
        link,
        quantity,
        price,
        status: OrderStatus.PENDING,
        createdAt: new Date().toISOString(),
        progress: 0
      };

      setOrders(prev => [newOrder, ...prev]);
      setBalance(balance - price);
      setIsProcessing(false);
      navigate('/orders');
    }, 1500);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8">
      <div className="bg-white dark:bg-gray-900 p-8 rounded-3xl border border-gray-200 dark:border-gray-800 shadow-sm">
        <h2 className="text-2xl font-bold mb-8 dark:text-white">Create New Order</h2>
        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid sm:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-400 mb-2">Select Platform</label>
              <div className="grid grid-cols-2 gap-2">
                {Object.values(Platform).map(p => (
                  <button
                    key={p}
                    type="button"
                    onClick={() => setPlatform(p)}
                    className={`flex items-center gap-2 px-4 py-3 rounded-xl border text-sm font-bold transition-all ${
                      platform === p 
                        ? 'bg-purple-600 border-purple-600 text-white shadow-md' 
                        : 'border-gray-200 dark:border-gray-800 dark:text-white hover:bg-gray-50 dark:hover:bg-gray-800'
                    }`}
                  >
                    {PLATFORM_LOGOS[p]}
                    {p}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-400 mb-2">Service Type</label>
              <div className="grid grid-cols-2 gap-2">
                {Object.values(ServiceType).map(s => (
                  <button
                    key={s}
                    type="button"
                    onClick={() => setService(s)}
                    className={`px-4 py-3 rounded-xl border text-sm font-bold transition-all ${
                      service === s 
                        ? 'bg-purple-600 border-purple-600 text-white shadow-md' 
                        : 'border-gray-200 dark:border-gray-800 dark:text-white hover:bg-gray-50 dark:hover:bg-gray-800'
                    }`}
                  >
                    {s}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-400 mb-2">Target Link</label>
            <input 
              type="url"
              required
              placeholder="https://www.instagram.com/p/..."
              className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-gray-800 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-purple-600 transition-all"
              value={link}
              onChange={e => setLink(e.target.value)}
            />
            <p className="text-[10px] text-gray-500 mt-2">Make sure the account/post is PUBLIC.</p>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-400 mb-2">Quantity (Min: 100)</label>
            <input 
              type="number"
              min="100"
              max="500000"
              required
              className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-gray-800 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-purple-600 transition-all"
              value={quantity}
              onChange={e => setQuantity(Number(e.target.value))}
            />
          </div>

