            <div>
              <p className="text-sm text-purple-600 dark:text-purple-400 font-bold uppercase tracking-wider">Estimated Total</p>
              <p className="text-3xl font-black text-purple-900 dark:text-white">₦{price.toLocaleString()}</p>
            </div>
            <button 
              type="submit"
              disabled={isProcessing}
              className={`px-10 py-4 bg-purple-600 text-white rounded-xl font-bold hover:bg-purple-700 transition-all shadow-lg shadow-purple-200 dark:shadow-none flex items-center gap-2 ${isProcessing ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
              {isProcessing ? 'Processing...' : 'Place Order'}
            </button>
