const NewOrderPage = () => {
  const { balance, setBalance, setOrders } = useApp();
  const navigate = useNavigate();
  const [platform, setPlatform] = useState<Platform>(Platform.INSTAGRAM);
  const [service, setService] = useState<ServiceType>(ServiceType.FOLLOWERS);
  const [quantity, setQuantity] = useState(100);
  const [link, setLink] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  const price = Math.round(quantity * PRICING[service]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (balance < price) {
      alert("Insufficient balance. Please fund your wallet.");
      return;
    }

    setIsProcessing(true);
    setTimeout(() => {
      const newOrder: Order = {
        id: 'ORD-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
        userId: 'current',
        platform,
        service,
        link,
        quantity,
        price,
        status: OrderStatus.PENDING,
        createdAt: new Date().toISOString(),
        progress: 0
      };

      setOrders(prev => [newOrder, ...prev]);
      setBalance(balance - price);
      setIsProcessing(false);
      navigate('/orders');
    }, 1500);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8">
      <div className="bg-white dark:bg-gray-900 p-8 rounded-3xl border border-gray-200 dark:border-gray-800 shadow-sm">
