export enum Platform {
  FACEBOOK = 'Facebook',
  TIKTOK = 'TikTok',
  INSTAGRAM = 'Instagram',
  YOUTUBE = 'YouTube'
}

export enum ServiceType {
  FOLLOWERS = 'Followers',
  LIKES = 'Likes',
  VIEWS = 'Views',
  COMMENTS = 'Comments'
}

export enum OrderStatus {
  PENDING = 'Pending',
  PROCESSING = 'Processing',
  COMPLETED = 'Completed',
  PARTIAL = 'Partial',
  REFUNDED = 'Refunded'
}

export interface User {
  id: string;
  username: string;
  email: string;
  role: 'user' | 'admin';
  balance: number;
  apiKey: string;
  referralCode: string;
  referredBy?: string;
  referralEarnings: number;
  createdAt: string;
}

export interface Order {
  id: string;
  userId: string;
  platform: Platform;
  service: ServiceType;
  link: string;
  quantity: number;
  price: number;
  status: OrderStatus;
  createdAt: string;
  progress: number;
  dripFeed?: {
    runs: number;
    interval: number; // minutes
  };
  autoRefill: boolean;
  comments?: string[];
}

export interface Transaction {
  id: string;
  userId: string;
  username: string;
  amount: number;
  status: 'pending' | 'approved' | 'rejected';
  proofUrl?: string;
  createdAt: string;
}

export interface Ticket {
  id: string;
  userId: string;
  username: string;
  subject: string;
  category: 'Order Issue' | 'Payment Query' | 'Feature Request' | 'Other';
  status: 'Open' | 'Resolved';
  messages: {
    sender: 'user' | 'admin';
    content: string;
    timestamp: string;
  }[];
  createdAt: string;
