const NewOrderPage = () => {
  const { balance, setBalance, setOrders } = useApp();
  const navigate = useNavigate();
  const [platform, setPlatform] = useState<Platform>(Platform.INSTAGRAM);
  const [service, setService] = useState<ServiceType>(ServiceType.FOLLOWERS);
  const [link, setLink] = useState('');
  const [quantity, setQuantity] = useState(100);
  const [dripRuns, setDripRuns] = useState(1);
  const [dripInterval, setDripInterval] = useState(60);
  const [autoRefill, setAutoRefill] = useState(false);
  const [customComments, setCustomComments] = useState('');

  const totalPrice = useMemo(() => Math.round(quantity * PRICING[service] * dripRuns), [quantity, service, dripRuns]);

  const handlePlaceOrder = (e: React.FormEvent) => {
    e.preventDefault();
    if (balance < totalPrice) return alert("Insufficient funds.");

    const newOrder: Order = {
      id: generateID('ORD'),
      userId: 'current',
      platform,
      service,
      link,
      quantity,
      price: totalPrice,
      status: OrderStatus.PENDING,
      createdAt: new Date().toISOString(),
      progress: 0,
      dripFeed: dripRuns > 1 ? { runs: dripRuns, interval: dripInterval } : undefined,
      autoRefill,
      comments: service === ServiceType.COMMENTS ? customComments.split('\n').filter(c => c.trim()) : undefined
    };

    setOrders(prev => [newOrder, ...prev]);
    setBalance(balance - totalPrice);
    navigate('/orders');
  };

  return (
    <div className="max-w-4xl mx-auto grid lg:grid-cols-5 gap-8">
      <div className="lg:col-span-3 bg-white dark:bg-gray-900 rounded-3xl border border-gray-100 dark:border-gray-800 p-8 shadow-sm">
        <h2 className="text-2xl font-black mb-8 dark:text-white flex items-center gap-2">
          <ShoppingCartIcon className="w-8 h-8 text-purple-600" />
          Create Order
        </h2>
        <form onSubmit={handlePlaceOrder} className="space-y-6">
          <div className="grid grid-cols-2 gap-3">
            {Object.values(Platform).map(p => (
              <button key={p} type="button" onClick={() => setPlatform(p)} className={`flex items-center gap-2 p-4 rounded-2xl border text-xs font-bold transition-all ${platform === p ? 'bg-purple-600 text-white border-purple-600' : 'bg-gray-50 dark:bg-gray-800 text-gray-500 border-transparent hover:border-purple-200'}`}>
                {PLATFORM_LOGOS[p]} {p}
              </button>
            ))}
          </div>
          <div className="grid grid-cols-2 gap-3">
            {Object.values(ServiceType).map(s => (
              <button key={s} type="button" onClick={() => setService(s)} className={`p-4 rounded-2xl border text-xs font-bold transition-all ${service === s ? 'bg-purple-600 text-white border-purple-600' : 'bg-gray-50 dark:bg-gray-800 text-gray-500 border-transparent hover:border-purple-200'}`}>
                {s}
              </button>
            ))}
          </div>
          <div className="space-y-2">
            <label className="text-xs font-bold text-gray-400 uppercase">Target Link</label>
            <input required type="url" value={link} onChange={e => setLink(e.target.value)} placeholder="https://..." className="w-full bg-gray-50 dark:bg-gray-800 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-purple-600 outline-none dark:text-white" />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-400 uppercase">Quantity (Min 100)</label>
              <input type="number" min="100" value={quantity} onChange={e => setQuantity(Number(e.target.value))} className="w-full bg-gray-50 dark:bg-gray-800 rounded-xl px-4 py-3 text-sm outline-none dark:text-white" />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-400 uppercase">Runs (Drip Feed)</label>
              <input type="number" min="1" value={dripRuns} onChange={e => setDripRuns(Number(e.target.value))} className="w-full bg-gray-50 dark:bg-gray-800 rounded-xl px-4 py-3 text-sm outline-none dark:text-white" />
            </div>
          </div>
          {service === ServiceType.COMMENTS && (
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-400 uppercase">Custom Comments (One per line)</label>
              <textarea rows={4} value={customComments} onChange={e => setCustomComments(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-800 rounded-xl px-4 py-3 text-sm outline-none dark:text-white" placeholder="Great post!&#10;Love this!"></textarea>
            </div>
          )}
          <div className="flex items-center gap-3 p-4 bg-purple-50 dark:bg-purple-900/10 rounded-2xl">
            <input type="checkbox" id="refill" checked={autoRefill} onChange={e => setAutoRefill(e.target.checked)} className="w-5 h-5 accent-purple-600" />
            <label htmlFor="refill" className="text-sm font-bold text-purple-700 dark:text-purple-400">Enable 30-Day Auto-Refill Guarantee</label>
          </div>
          <button type="submit" className="w-full py-4 bg-purple-600 text-white rounded-2xl font-bold shadow-lg shadow-purple-200 hover:bg-purple-700 transition-all">Place Order - ₦{totalPrice.toLocaleString()}</button>
        </form>
      </div>
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-yellow-50 dark:bg-yellow-900/10 p-6 rounded-3xl border border-yellow-100 dark:border-yellow-800">
          <h4 className="font-black text-yellow-800 dark:text-yellow-400 mb-2">Order Guidelines</h4>
          <ul className="text-xs text-yellow-700 dark:text-yellow-500 space-y-2 list-disc list-inside">
            <li>Ensure account is NOT private.</li>
            <li>Double-check the link before submitting.</li>
            <li>Do not order same link from multiple panels at once.</li>
            <li>Drip-feed interval is set to 60 mins by default.</li>
          </ul>
        </div>
        <div className="bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800 rounded-3xl p-6 text-center shadow-sm">
          <p className="text-sm text-gray-500 mb-2">Current Wallet Balance</p>
          <p className="text-3xl font-black text-purple-600">₦{balance.toLocaleString()}</p>
          <Link to="/wallet" className="mt-4 inline-block text-xs font-bold text-purple-600 underline">Add Funds</Link>
        </div>
      </div>
    </div>
  );
};

