const MassOrderPage = () => {
  const { user, setUser, setOrders } = useApp();
  const navigate = useNavigate();
  const [input, setInput] = useState('');

  const handleMassOrder = () => {
    if (!user) return;
    const lines = input.split('\n').filter(l => l.trim());
    const newOrders: Order[] = [];
    let totalCost = 0;

    lines.forEach(line => {
      const parts = line.split('|').map(p => p.trim());
      if (parts.length === 3) {
        const [serviceKey, target, qty] = parts;
        const q = parseInt(qty);
        const cost = Math.round(q * 1.1); // Simple flat rate for mass order mock
        totalCost += cost;

        newOrders.push({
          id: generateID('ORD'),
          userId: user.id,
          platform: Platform.INSTAGRAM,
          service: ServiceType.FOLLOWERS,
          link: target,
          quantity: q,
          price: cost,
          status: OrderStatus.PENDING,
          createdAt: new Date().toISOString(),
          progress: 0,
          autoRefill: true
        });
      }
    });

    if (user.balance < totalCost) return alert("Insufficient balance.");
    setUser({ ...user, balance: user.balance - totalCost });
    setOrders(prev => [...newOrders, ...prev]);
    navigate('/orders');
  };

  return (
    <div className="max-w-3xl mx-auto bg-white dark:bg-gray-900 p-8 rounded-[40px] border dark:border-gray-800 shadow-xl">
      <h2 className="text-2xl font-black mb-4 dark:text-white">Mass Order</h2>
      <p className="text-sm text-gray-500 mb-6">Format: <code className="bg-gray-100 dark:bg-gray-800 p-1 rounded">service_id | link | quantity</code> (One per line)</p>
      <textarea rows={10} value={input} onChange={e => setInput(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-800 rounded-3xl p-6 text-sm outline-none focus:ring-2 focus:ring-purple-600 dark:text-white font-mono" placeholder="INSTA_FOLLOW | https://... | 1000"></textarea>
      <button onClick={handleMassOrder} className="w-full mt-6 py-5 bg-purple-600 text-white rounded-2xl font-black shadow-xl shadow-purple-200">Submit All Orders</button>
    </div>
  );
};

