const NewOrderPage = () => {
  const { user, setUser, setOrders } = useApp();
  const navigate = useNavigate();
  const [platform, setPlatform] = useState<Platform>(Platform.INSTAGRAM);
  const [service, setService] = useState<ServiceType>(ServiceType.FOLLOWERS);
  const [link, setLink] = useState('');
  const [quantity, setQuantity] = useState(100);
  const [showSuccess, setShowSuccess] = useState(false);
  const [lastServiceName, setLastServiceName] = useState('');

  const price = Math.round(quantity * PRICING[service]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    if (user.balance < price) return alert("Insufficient balance. Please fund your wallet.");

    const newOrder: Order = {
      id: generateID('ORD'),
      userId: user.id,
      platform,
      service,
      link,
      quantity,
      price,
      status: OrderStatus.PENDING,
      createdAt: new Date().toISOString(),
      progress: 0,
      autoRefill: true
    };

    const updatedUser = { ...user, balance: user.balance - price };
    setUser(updatedUser);
    setOrders(prev => [newOrder, ...prev]);
    setLastServiceName(`${platform} ${service}`);
    setShowSuccess(true);
  };

  return (
    <div className="max-w-3xl mx-auto bg-white dark:bg-gray-900 p-10 rounded-[50px] border dark:border-gray-800 shadow-2xl relative overflow-hidden animate-in zoom-in-95 duration-500">
      <SuccessModal isOpen={showSuccess} onClose={() => { setShowSuccess(false); navigate('/orders'); }} serviceName={lastServiceName} />

      <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500/5 rounded-full -translate-y-12 translate-x-12"></div>

      <h2 className="text-3xl font-black mb-10 dark:text-white flex items-center gap-4">
        <div className="p-3 bg-purple-100 dark:bg-purple-900/30 rounded-2xl"><ShoppingCartIcon className="w-8 h-8 text-purple-600" /></div>
        Custom Order
      </h2>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div className="space-y-3">
          <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Platform</label>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            {Object.values(Platform).map(p => (
              <button key={p} type="button" onClick={() => setPlatform(p)} className={`p-4 rounded-2xl border-2 text-xs font-bold transition-all flex flex-col items-center gap-2 ${platform === p ? 'bg-purple-600 text-white border-purple-600 shadow-lg shadow-purple-100 dark:shadow-none' : 'bg-gray-50 dark:bg-gray-800 border-transparent text-gray-500'}`}>
                <div className={platform === p ? 'text-white' : 'text-purple-600'}>{PLATFORM_LOGOS[p]}</div>
                {p}
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-3">
          <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Engagement Type</label>
          <div className="grid grid-cols-2 gap-3">
            {Object.values(ServiceType).map(s => (
              <button key={s} type="button" onClick={() => setService(s)} className={`p-5 rounded-2xl border-2 text-sm font-black transition-all ${service === s ? 'bg-purple-600 text-white border-purple-600 shadow-md' : 'bg-gray-50 dark:bg-gray-800 border-transparent text-gray-400'}`}>
                {s}
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-4">
          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Destination URL</label>
            <input required type="url" value={link} onChange={e => setLink(e.target.value)} placeholder="https://www.instagram.com/p/..." className="w-full bg-gray-50 dark:bg-gray-800 rounded-3xl px-8 py-5 text-sm outline-none focus:ring-4 focus:ring-purple-600/10 transition-all dark:text-white" />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Order Quantity</label>
            <input required type="number" min="50" value={quantity} onChange={e => setQuantity(Number(e.target.value))} className="w-full bg-gray-50 dark:bg-gray-800 rounded-3xl px-8 py-5 text-sm outline-none focus:ring-4 focus:ring-purple-600/10 transition-all dark:text-white" />
          </div>
        </div>

        <div className="p-8 bg-purple-50 dark:bg-purple-900/10 rounded-[40px] border border-purple-100 dark:border-purple-800 flex flex-col sm:flex-row justify-between items-center gap-6">
          <div className="text-center sm:text-left">
            <p className="text-[10px] font-black text-purple-600 dark:text-purple-400 uppercase tracking-widest mb-1">Total Bill</p>
            <p className="text-4xl font-black text-purple-900 dark:text-white">₦{price.toLocaleString()}</p>
          </div>
          <button type="submit" className="w-full sm:w-auto px-12 py-5 bg-purple-600 text-white rounded-3xl font-black text-lg shadow-xl shadow-purple-200 hover:bg-purple-700 hover:scale-105 transition-all">Place Order Now</button>
        </div>
      </form>
    </div>
  );
};

