const MassOrderPage = () => {
  const { user, setUser, setOrders } = useApp();
  const navigate = useNavigate();
  const [input, setInput] = useState('');

  const handleMassOrder = () => {
    if (!user) return;
    const lines = input.split('\n').filter(l => l.trim());
    const newOrders: Order[] = [];
    let totalCost = 0;

    lines.forEach(line => {
      const parts = line.split('|').map(p => p.trim());
      if (parts.length === 3) {
        const [_, target, qty] = parts;
        const q = parseInt(qty);
        const cost = Math.round(q * 1.1);
        totalCost += cost;

        newOrders.push({
          id: generateID('ORD'),
          userId: user.id,
          platform: Platform.INSTAGRAM,
          service: ServiceType.FOLLOWERS,
          link: target,
          quantity: q,
          price: cost,
          status: OrderStatus.PENDING,
          createdAt: new Date().toISOString(),
          progress: 0,
          autoRefill: true
        });
      }
    });

    if (user.balance < totalCost) return alert("Insufficient balance.");
    setUser({ ...user, balance: user.balance - totalCost });
    setOrders(prev => [...newOrders, ...prev]);
    navigate('/orders');
  };

  return (
    <div className="max-w-4xl mx-auto bg-white dark:bg-gray-900 p-12 rounded-[50px] border dark:border-gray-800 shadow-2xl animate-in fade-in duration-500">
      <h2 className="text-3xl font-black mb-6 dark:text-white">Mass Deploy</h2>
      <p className="text-sm text-gray-500 mb-8 leading-relaxed">Place multiple orders at once. Use the format: <br/><code className="bg-purple-100 dark:bg-purple-900/30 text-purple-600 px-3 py-1 rounded-lg font-bold">service_id | link | quantity</code> (One per line)</p>
      <textarea rows={10} value={input} onChange={e => setInput(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-800 rounded-[40px] p-8 text-sm outline-none focus:ring-4 focus:ring-purple-600/10 dark:text-white font-mono" placeholder="INSTA_FOLLOW | https://... | 1000&#10;TIKTOK_VIEWS | https://... | 5000"></textarea>
      <button onClick={handleMassOrder} className="w-full mt-8 py-5 bg-purple-600 text-white rounded-3xl font-black text-lg shadow-xl shadow-purple-100 hover:scale-[1.02] transition-all">Execute All Orders</button>
    </div>
  );
};

