const NewOrderPage = () => {
  const { user, setUser, setOrders } = useApp();
  const navigate = useNavigate();
  const [platform, setPlatform] = useState<Platform>(Platform.INSTAGRAM);
  const [service, setService] = useState<ServiceType>(ServiceType.FOLLOWERS);
  const [link, setLink] = useState('');
  const [quantity, setQuantity] = useState(100);
  const [showSuccess, setShowSuccess] = useState(false);
  const [lastServiceName, setLastServiceName] = useState('');

  const price = useMemo(() => Math.round(quantity * PRICING[service]), [quantity, service]);
  const hasBalance = (user?.balance || 0) >= price;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    if (!hasBalance) return alert("Insufficient balance. Please fund your wallet first.");

    const newOrder: Order = {
      id: generateID('ORD'),
      userId: user.id,
      platform,
      service,
      link,
      quantity,
      price,
      status: OrderStatus.PENDING,
      createdAt: new Date().toISOString(),
      progress: 0,
      autoRefill: true
    };

    // Correctly update global balance
    const updatedUser = { ...user, balance: user.balance - price };
    setUser(updatedUser);
    setOrders(prev => [newOrder, ...prev]);
    setLastServiceName(`${platform} ${service}`);
    setShowSuccess(true);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <SuccessModal isOpen={showSuccess} onClose={() => { setShowSuccess(false); navigate('/orders'); }} serviceName={lastServiceName} />

