          <div className="space-y-4">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] ml-2">Target Platform</label>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              {Object.values(Platform).map(p => (
                <button key={p} type="button" onClick={() => setPlatform(p)} className={`p-6 rounded-[35px] border-4 text-xs font-black transition-all flex flex-col items-center gap-4 ${platform === p ? 'bg-purple-600 text-white border-purple-600 shadow-2xl shadow-purple-200 dark:shadow-none' : 'bg-gray-50 dark:bg-gray-800 border-transparent text-gray-400'}`}>
