            <div className="grid grid-cols-2 gap-4">
              {Object.values(ServiceType).map(s => (
                <button key={s} type="button" onClick={() => setService(s)} className={`p-6 rounded-[35px] border-4 text-sm font-black transition-all ${service === s ? 'bg-purple-600 text-white border-purple-600 shadow-xl' : 'bg-gray-50 dark:bg-gray-800 border-transparent text-gray-400'}`}>
