const AdminPaymentsControl = () => {
  const { transactions, setTransactions, users, setUsers } = useApp();

  const approve = (tx: Transaction) => {
    // 1. Update the transaction to 'approved'
    setTransactions(prev => prev.map(t => t.id === tx.id ? {...t, status: 'approved'} : t));

    // 2. Increment the balance of the specific user in the global users table
    setUsers(prev => prev.map(u => {
      if (u.id === tx.userId) {
        // If the user being approved is the current session user, update that too
        const storedUser = localStorage.getItem('user');
        if (storedUser) {
          const parsed = JSON.parse(storedUser);
          if (parsed.id === u.id) {
            localStorage.setItem('user', JSON.stringify({...parsed, balance: parsed.balance + tx.amount}));
          }
        }
        return { ...u, balance: u.balance + tx.amount };
      }
      return u;
    }));

    alert(`Success! ₦${tx.amount.toLocaleString()} has been added to ${tx.username}'s balance.`);
  };

  return (
    <div className="max-w-4xl mx-auto animate-in fade-in duration-500">
      <div className="bg-white dark:bg-gray-900 rounded-[50px] p-12 shadow-2xl border dark:border-gray-800">
        <h2 className="text-3xl font-black mb-10 dark:text-white flex items-center gap-4">
          <BanknotesIcon className="w-10 h-10 text-green-600" />
          Verify Bank Transfers
        </h2>
        <div className="space-y-6">
          {transactions.filter(t => t.status === 'pending').map(t => (
            <div key={t.id} className="flex flex-col sm:flex-row items-center justify-between p-8 bg-gray-50 dark:bg-gray-800 rounded-[40px] gap-6 border-4 border-transparent hover:border-purple-200 transition-all shadow-sm">
              <div className="text-center sm:text-left">
                <p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-1">User Reference</p>
                <p className="text-2xl font-black dark:text-white tracking-tighter">{t.username}</p>
                <p className="text-xs text-purple-600 font-black mt-1">{t.id}</p>
              </div>
              <div className="text-center sm:text-right">
                <p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-1">Amount Sent</p>
                <p className="text-3xl font-black text-green-600">₦{t.amount.toLocaleString()}</p>
              </div>
              <div className="flex gap-4">
                <button onClick={() => approve(t)} className="px-10 py-4 bg-green-600 text-white rounded-[25px] text-xs font-black uppercase hover:bg-green-700 shadow-xl shadow-green-100 transition-all">APPROVE</button>
                <button className="px-10 py-4 bg-red-600 text-white rounded-[25px] text-xs font-black uppercase hover:bg-red-700 shadow-xl shadow-red-100 transition-all">REJECT</button>
              </div>
            </div>
          ))}
          {transactions.filter(t => t.status === 'pending').length === 0 && (
            <div className="text-center py-24 opacity-30">
              <CheckBadgeIcon className="w-20 h-20 mx-auto mb-4" />
              <p className="text-2xl font-black">All verifications clear.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

