        </div>

        <form onSubmit={handleAuth} className="space-y-4">
          {step === 'info' ? (
            <>
              <input required type="email" placeholder="Gmail Address" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-[#1C1F2E] border-none rounded-2xl px-6 py-5 outline-none focus:ring-2 focus:ring-purple-600 transition-all" />
              <input required type="password" placeholder="Password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full bg-[#1C1F2E] border-none rounded-2xl px-6 py-5 outline-none focus:ring-2 focus:ring-purple-600 transition-all" />
