const NewOrderPage = () => {
  const { user, setUser, setOrders } = useApp();
  const navigate = useNavigate();
  const [platform, setPlatform] = useState<Platform>(Platform.FACEBOOK);
  const [selectedServiceId, setSelectedServiceId] = useState('');
  const [link, setLink] = useState('');
  const [quantity, setQuantity] = useState(100);

  const availableServices = PLATFORM_SERVICES[platform];
  const activeService = availableServices.find(s => s.id === selectedServiceId) || availableServices[0];

  const totalPrice = Math.round((quantity * activeService.pricePer1000) / 1000);
  const canAfford = (user?.balance || 0) >= totalPrice;

  const handlePlaceOrder = (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    if (!canAfford) return alert("Insufficient balance! Please fund your wallet first.");

    const newOrder: Order = {
      id: generateID('ORD'),
      userId: user.id,
      platform,
      service: activeService.name,
      link,
      quantity,
      price: totalPrice,
      status: OrderStatus.PENDING,
      createdAt: new Date().toISOString(),
      progress: 0,
      autoRefill: true
    };

    setUser({...user, balance: user.balance - totalPrice});
    setOrders(prev => [newOrder, ...prev]);
    navigate('/congratulations', { state: { service: activeService.name } });
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="bg-[#151720] rounded-[30px] p-8 border border-gray-800 shadow-xl">
        <h3 className="text-gray-400 text-[10px] font-black uppercase tracking-widest mb-4">Platform</h3>
        <div className="grid grid-cols-2 gap-3 mb-8">
          {Object.values(Platform).map(p => (
            <button key={p} onClick={() => {setPlatform(p); setSelectedServiceId('');}} className={`flex flex-col items-center justify-center gap-3 p-6 rounded-3xl transition-all border-2 ${platform === p ? 'bg-purple-600 border-purple-500 text-white' : 'bg-[#1C1F2E] border-transparent text-gray-500 hover:bg-[#252839]'}`}>
              {PLATFORM_LOGOS[p]}
              <span className="text-[10px] font-bold uppercase">{p}</span>
            </button>
          ))}
        </div>

        <div className="space-y-6">
          <div>
            <label className="text-gray-400 text-[10px] font-black uppercase tracking-widest block mb-3">Service</label>
            <select value={selectedServiceId} onChange={e => setSelectedServiceId(e.target.value)} className="w-full bg-[#1C1F2E] border-none rounded-2xl px-6 py-5 text-sm text-white outline-none focus:ring-2 focus:ring-purple-600">
              {availableServices.map(s => (
                <option key={s.id} value={s.id}>{s.name} - ₦{s.pricePer1000}/1k</option>
              ))}
            </select>
          </div>

          <div>
            <label className="text-gray-400 text-[10px] font-black uppercase tracking-widest block mb-3">Destination URL</label>
            <input required type="url" value={link} onChange={e => setLink(e.target.value)} placeholder="https://..." className="w-full bg-[#1C1F2E] border-none rounded-2xl px-6 py-5 text-sm text-white outline-none focus:ring-2 focus:ring-purple-600" />
          </div>

          <div>
            <label className="text-gray-400 text-[10px] font-black uppercase tracking-widest block mb-3">Quantity</label>
            <input required type="number" min="50" value={quantity} onChange={e => setQuantity(Number(e.target.value))} className="w-full bg-[#1C1F2E] border-none rounded-2xl px-6 py-5 text-sm text-white outline-none focus:ring-2 focus:ring-purple-600" />
          </div>

          <div className="pt-4">
