const LoginPage = () => {
  const { setUser, users, setUsers } = useApp();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [isLogin, setIsLogin] = useState(true);
  const [step, setStep] = useState<'info' | 'verify'>('info');

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();

    if (isLogin) {
      if (formData.email === ADMIN_CREDENTIALS.email && formData.password === ADMIN_CREDENTIALS.password) {
        const admin: User = {
          id: 'admin-1',
          username: 'Admin John',
          email: ADMIN_CREDENTIALS.email,
          role: 'admin',
          balance: 999999,
          apiKey: 'MASTER_KEY',
          referralCode: 'ADMIN',
          referralEarnings: 0,
          createdAt: new Date().toISOString()
        };
        setUser(admin);
        navigate('/admin');
        return;
      }

      const foundUser = users.find(u => u.email === formData.email && u.password === formData.password);
      if (foundUser) {
        setUser(foundUser);
        navigate('/dashboard');
      } else {
        const exists = users.some(u => u.email === formData.email);
        if (!exists) {
          alert("This email is not registered. Please sign up first to login.");
          setIsLogin(false);
        } else {
          alert("Incorrect password. Please try again.");
        }
      }
    } else {
      if (step === 'info') {
        if (users.some(u => u.email === formData.email)) return alert("Email already in use. Please login.");
        setStep('verify');
      } else {
        const newUser: User = {
          id: generateID('USR'),
          username: formData.email.split('@')[0],
          email: formData.email,
          password: formData.password,
          role: 'user',
          balance: 0,
          apiKey: generateID('KEY'),
          referralCode: generateID('REF'),
          referralEarnings: 0,
          createdAt: new Date().toISOString()
        };
        setUsers(prev => [...prev, newUser]);
        setUser(newUser);
        navigate('/dashboard');
      }
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#05060A] p-6 text-white">
      <div className="max-w-md w-full bg-[#0D0F18] rounded-[40px] p-12 border border-white/5 shadow-2xl animate-in slide-in-from-bottom-4 duration-500">
        <div className="text-center mb-10">
          <div className="w-16 h-16 bg-purple-600 rounded-2xl flex items-center justify-center text-white font-black text-3xl mx-auto mb-6">T</div>
          <h2 className="text-3xl font-black tracking-tight">{step === 'verify' ? 'Verification' : (isLogin ? 'Sign In' : 'Sign Up')}</h2>
          <p className="text-gray-500 text-xs mt-2 uppercase tracking-[0.2em] font-bold">TomSociaGrow Platform</p>
        </div>

        <form onSubmit={handleAuth} className="space-y-4">
          {step === 'info' ? (
            <>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-500 uppercase ml-2">Gmail Address</label>
                <input required type="email" placeholder="example@gmail.com" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-[#161924] border border-white/5 rounded-2xl px-6 py-5 outline-none focus:ring-2 focus:ring-purple-600 transition-all text-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-500 uppercase ml-2">Secure Password</label>
                <input required type="password" placeholder="••••••••" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full bg-[#161924] border border-white/5 rounded-2xl px-6 py-5 outline-none focus:ring-2 focus:ring-purple-600 transition-all text-sm" />
              </div>
              <button type="submit" className="w-full py-5 bg-purple-600 rounded-2xl font-black text-lg shadow-xl shadow-purple-900/10 hover:bg-purple-700 active:scale-[0.98] transition-all">
                {isLogin ? 'Enter Dashboard' : 'Continue'}
              </button>
            </>
          ) : (
            <div className="space-y-6">
              <p className="text-center text-xs text-gray-400">A verification code was sent to <span className="text-purple-500 font-bold">{formData.email}</span>. Please check your inbox.</p>
              <input required type="text" maxLength={6} placeholder="000 000" className="w-full bg-[#161924] border-none rounded-2xl px-6 py-5 text-center text-2xl font-black tracking-widest outline-none focus:ring-2 focus:ring-purple-600 transition-all" />
              <button type="submit" className="w-full py-5 bg-purple-600 rounded-2xl font-black text-lg">Verify & Finish</button>
              <button type="button" onClick={() => setStep('info')} className="w-full text-[10px] font-black text-gray-500 uppercase underline">Change Email</button>
            </div>
          )}
        </form>

        <div className="mt-10 text-center">
          <button onClick={() => {setIsLogin(!isLogin); setStep('info');}} className="text-purple-500 font-black text-xs uppercase tracking-widest border-b-2 border-purple-500/20 pb-1 hover:border-purple-500 transition-all">
            {isLogin ? "Create your free account" : "I already have an account"}
          </button>
        </div>
      </div>
    </div>
  );
};

