      </div>

      <div className="space-y-6">
        {orders.map(o => (
          <div key={o.id} className="bg-[#0D0F18] rounded-[40px] p-10 border border-white/5 shadow-2xl space-y-8 animate-in fade-in duration-500">
             <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
               <div className="flex items-center gap-6">
                  <div className="p-5 bg-[#161924] rounded-[25px] text-purple-500">{PLATFORM_LOGOS[o.platform]}</div>
                  <div>
                    <h4 className="text-xl font-black">{o.service}</h4>
                    <p className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mt-1">ID: {o.id} • QTY: {o.quantity.toLocaleString()}</p>
                  </div>
               </div>
               <div className="flex items-center gap-6">
                  <div className="text-right">
                    <p className="text-2xl font-black text-green-500">₦{o.price.toLocaleString()}</p>
                    <p className="text-[10px] font-black text-gray-500 uppercase mt-1">{new Date(o.createdAt).toLocaleDateString()}</p>
                  </div>
                  <span className={`px-4 py-2 rounded-full text-[10px] font-black uppercase ${o.status === OrderStatus.COMPLETED ? 'bg-green-500/10 text-green-500 border border-green-500/20' : 'bg-yellow-500/10 text-yellow-500 border border-yellow-500/20'}`}>{o.status}</span>
               </div>
             </div>

             <div className="bg-[#161924] p-6 rounded-[25px] flex items-center justify-between gap-6 border border-white/5">
                {editingId === o.id ? (
                  <input value={tempLink} onChange={e => setTempLink(e.target.value)} className="flex-1 bg-transparent border-none outline-none text-xs text-purple-400 font-mono" />
                ) : (
                  <p className="flex-1 text-xs text-gray-500 font-mono truncate">{o.link}</p>
                )}
                <div className="flex gap-2">
                   <button onClick={() => copyToClipboard(o.link)} className="p-3 bg-white/5 hover:bg-white/10 rounded-xl transition-all" title="Copy Link"><ClipboardDocumentCheckIcon className="w-5 h-5 text-gray-400" /></button>
                   {editingId === o.id ? (
                     <button onClick={() => handleSaveLink(o.id)} className="px-4 bg-green-600 rounded-xl text-[10px] font-black uppercase">Save</button>
                   ) : (
                     <button onClick={() => {setEditingId(o.id); setTempLink(o.link);}} className="p-3 bg-white/5 hover:bg-white/10 rounded-xl transition-all" title="Edit Link"><PencilSquareIcon className="w-5 h-5 text-gray-400" /></button>
                   )}
                </div>
             </div>

             <div className="flex flex-wrap gap-2 pt-6 border-t border-white/5">
                {[OrderStatus.PENDING, OrderStatus.PROCESSING, OrderStatus.CONFIRMED, OrderStatus.APPROVED, OrderStatus.COMPLETED].map(s => (
                  <button key={s} onClick={() => updateStatus(o.id, s)} className={`px-5 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${o.status === s ? 'bg-purple-600 text-white shadow-xl shadow-purple-900/10' : 'bg-white/5 text-gray-500 hover:text-white hover:bg-white/10'}`}>
                    {s}
                  </button>
                ))}
             </div>
          </div>
        ))}
        {orders.length === 0 && <div className="text-center py-32 opacity-20 font-black text-2xl">Queue is empty.</div>}
      </div>
    </div>
  );
};

