          email: ADMIN_CREDENTIALS.email,
          role: 'admin',
          balance: 1000000,
          apiKey: 'ADMIN_API_KEY_SECURE',
          referralCode: 'ADMIN',
          referralEarnings: 0,
          createdAt: new Date().toISOString()
