                <label className="text-[10px] font-black text-gray-500 uppercase ml-2 tracking-widest">Gmail Account</label>
                <input required type="email" placeholder="john@gmail.com" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-[#161924] border-none rounded-2xl px-6 py-5 outline-none focus:ring-2 focus:ring-purple-600 transition-all text-sm font-medium placeholder-gray-600" />
