  const activeService = activeCategory.services.find(s => s.id === servId) || activeCategory.services[0];

  const totalPrice = Math.round((quantity * activeService.pricePer1000) / 1000);
  const canAfford = (user?.balance || 0) >= totalPrice;

  const handleOrder = (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    if (quantity < 50) return alert("CORRECTION: Minimum quantity is 50 for this service.");
    if (!canAfford) return alert("CORRECTION: Your balance is too low. Please fund your wallet first!");

    const newOrder: Order = {
      id: generateID('ORD'),
      userId: user.id,
      platform,
      service: activeService.name,
      link,
      quantity,
      price: totalPrice,
      status: OrderStatus.PENDING,
      createdAt: new Date().toISOString(),
      progress: 0,
      autoRefill: true
    };

    setUser({...user, balance: user.balance - totalPrice});
    setOrders(prev => [newOrder, ...prev]);
    navigate('/congratulations', { state: { service: activeService.name } });
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 text-white animate-in fade-in duration-500">
      <div className="bg-[#0D0F18] rounded-[40px] p-10 border border-white/5 shadow-2xl">
        <div className="mb-10">
          <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-4 ml-2">1. Select Destination</p>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            {Object.values(Platform).map(p => (
              <button key={p} onClick={() => {setPlatform(p); setCatId(''); setServId('');}} className={`flex flex-col items-center justify-center gap-4 p-6 rounded-[30px] border-2 transition-all ${platform === p ? 'bg-purple-600 border-purple-500 text-white shadow-xl shadow-purple-900/10 scale-[1.05]' : 'bg-[#161924] border-transparent text-gray-600 hover:bg-[#1C1F2E]'}`}>
                {PLATFORM_LOGOS[p]}
                <span className="text-[10px] font-black uppercase">{p}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-8">
          <div className="space-y-1.5">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-2">2. Category</p>
            <select value={catId} onChange={e => {setCatId(e.target.value); setServId('');}} className="w-full bg-[#161924] border-none rounded-[25px] px-8 py-5 text-sm font-black outline-none focus:ring-2 focus:ring-purple-600 transition-all cursor-pointer">
              {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>

          <div className="space-y-1.5">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-2">3. Service Package</p>
            <select value={servId} onChange={e => setServId(e.target.value)} className="w-full bg-[#161924] border-none rounded-[25px] px-8 py-5 text-sm font-black outline-none focus:ring-2 focus:ring-purple-600 transition-all cursor-pointer">
              {activeCategory.services.map(s => <option key={s.id} value={s.id}>{s.name} - ₦{s.pricePer1000}/1k</option>)}
            </select>
          </div>

          <div className="p-5 bg-white/5 rounded-3xl border border-white/5 flex items-start gap-4">
             <QuestionMarkCircleIcon className="w-6 h-6 text-purple-500 shrink-0" />
             <p className="text-xs text-gray-400 font-medium leading-relaxed">{activeService.description}</p>
          </div>

          <div className="space-y-1.5">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-2">4. Target URL / Link</p>
            <input required type="url" value={link} onChange={e => setLink(e.target.value)} placeholder="https://..." className="w-full bg-[#161924] border-none rounded-[25px] px-8 py-5 text-sm font-black outline-none focus:ring-2 focus:ring-purple-600 transition-all" />
          </div>

          <div className="space-y-1.5">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-2">5. Quantity (Min: 50)</p>
            <input required type="number" min="50" value={quantity} onChange={e => setQuantity(Number(e.target.value))} className="w-full bg-[#161924] border-none rounded-[25px] px-8 py-5 text-sm font-black outline-none focus:ring-2 focus:ring-purple-600 transition-all" />
          </div>

          <div className="pt-6">
             <div className="bg-[#161924] p-8 rounded-[35px] flex items-center justify-between mb-8 border border-white/5">
                <div>
                  <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">Total Cost</p>
                  <p className="text-4xl font-black">₦{totalPrice.toLocaleString()}</p>
                </div>
                {!canAfford && <div className="text-right"><span className="text-[9px] font-black text-red-500 bg-red-500/10 px-4 py-2 rounded-full border border-red-500/20 uppercase">Balance Too Low</span></div>}
             </div>
             <button onClick={handleOrder} className={`w-full py-6 rounded-[30px] font-black text-xl shadow-2xl transition-all ${canAfford ? 'bg-purple-600 text-white hover:bg-purple-700 active:scale-95 shadow-purple-900/20' : 'bg-white/5 text-gray-600 cursor-not-allowed'}`}>
               Confirm Order Now
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

