                     <button onClick={() => {setEditId(o.id); setTempLink(o.link);}} className="p-3 bg-white/5 rounded-xl hover:bg-white/10 transition-all"><PencilSquareIcon className="w-5 h-5 text-gray-400" /></button>
                   )}
