                  <button key={s} onClick={() => changeStatus(o.id, s)} className={`px-5 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${o.status === s ? 'bg-purple-600 text-white shadow-xl' : 'bg-white/5 text-gray-500 hover:text-white'}`}>
