                {PLATFORM_LOGOS[p]}
                <span className="text-[10px] font-black uppercase">{p}</span>
              </button>
            ))}
          </div>
        </div>
        <div className="space-y-6">
          <select value={catId} onChange={e => {setCatId(e.target.value); setServId('');}} className="w-full bg-[#161924] border-none rounded-[25px] px-8 py-5 text-sm font-black outline-none focus:ring-2 focus:ring-purple-600">
            {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
