                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-500 uppercase ml-4 tracking-widest">Amount Sent (₦)</label>
                  <input type="number" min="500" value={amt} onChange={e => setAmt(Number(e.target.value))} className="w-full bg-[#161924] rounded-[30px] px-10 py-6 text-2xl font-black outline-none border border-white/5 focus:ring-4 focus:ring-purple-600/10 transition-all" />
                </div>

                <div className="space-y-2">
