const SupportPage = () => {
  const { tickets, setTickets, user } = useApp();
  const [subject, setSubject] = useState('');

  const openTicket = () => {
    if (!subject) return;
    const newTicket: Ticket = {
      id: generateID('TKT'),
      userId: user?.id || '',
      username: user?.username || '',
      subject,
      status: 'Open',
      createdAt: new Date().toISOString(),
      lastUpdate: new Date().toISOString()
    };
    setTickets(prev => [newTicket, ...prev]);
    setSubject('');
    alert("Ticket created. Support will reply within 24h.");
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12 text-white">
      <div className="bg-[#0D0F18] p-12 rounded-[50px] border border-white/5 shadow-2xl">
        <h2 className="text-4xl font-black mb-12 tracking-tighter flex items-center gap-4"><ChatBubbleLeftRightIcon className="w-10 h-10 text-purple-500" /> Global Support</h2>
        <div className="space-y-6">
           <input type="text" value={subject} onChange={e => setSubject(e.target.value)} placeholder="Topic of enquiry" className="w-full bg-[#161924] border-none rounded-[25px] px-8 py-6 text-sm font-black outline-none focus:ring-2 focus:ring-purple-600 appearance-none" />
           <textarea rows={5} placeholder="Explain your situation in detail..." className="w-full bg-[#161924] border-none rounded-[35px] px-8 py-6 text-sm font-black outline-none focus:ring-2 focus:ring-purple-600 appearance-none" />
           <button onClick={openTicket} className="w-full py-6 bg-purple-600 rounded-[35px] font-black text-xl hover:bg-purple-700 active:scale-95 transition-all shadow-xl shadow-purple-900/20">Send Support Message</button>
        </div>
      </div>
      <div className="space-y-4">
        <h3 className="text-xl font-black mb-6">Conversation Logs</h3>
        {tickets.filter(t => t.userId === user?.id).map(t => (
           <div key={t.id} className="p-8 bg-[#0D0F18] border border-white/5 rounded-[40px] flex justify-between items-center group hover:border-white/10 transition-all">
              <div>
                <p className="text-lg font-black">{t.subject}</p>
                <p className="text-[10px] text-gray-500 font-bold uppercase mt-1">Ticket: {t.id} • {new Date(t.createdAt).toLocaleDateString()}</p>
              </div>
              <span className={`px-4 py-2 rounded-full text-[8px] font-black uppercase border ${t.status === 'Open' ? 'bg-green-500/10 text-green-500 border-green-500/20' : 'bg-gray-500/10 text-gray-500 border-gray-500/20'}`}>{t.status}</span>
           </div>
        ))}
        {tickets.filter(t => t.userId === user?.id).length === 0 && <div className="text-center py-10 opacity-20 font-bold italic">No active tickets.</div>}
      </div>
    </div>
  );
};

// --- Dashboard & Navigation ---

const Dashboard = () => {
