                <div className="flex items-center gap-6">
                   <div className="p-4 bg-[#0D0F18] rounded-[18px] text-purple-500 shadow-inner">{PLATFORM_LOGOS[o.platform]}</div>
                   <div>
                      <p className="text-lg font-black tracking-tight">{o.service}</p>
