      <div className="grid gap-4">
        {users.map(u => (
          <div key={u.id} className="p-8 bg-[#161924] rounded-[40px] border border-white/5 flex items-center justify-between group hover:border-purple-500/50 transition-all">
             <div className="flex items-center gap-6">
                <div className="w-14 h-14 bg-purple-600 rounded-2xl flex items-center justify-center font-black text-xl uppercase shadow-lg shadow-purple-900/20">
                  {u.username.charAt(0)}
                </div>
                <div>
