const AdminOrdersControl = () => {
  const { orders, setOrders } = useApp();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempLink, setTempLink] = useState('');

  const updateStatus = (id: string, s: OrderStatus) => {
    setOrders(prev => prev.map(o => o.id === id ? {...o, status: s} : o));
    alert(`Status updated to ${s}`);
  };

  const saveLink = (id: string) => {
    setOrders(prev => prev.map(o => o.id === id ? {...o, link: tempLink} : o));
    setEditingId(null);
    alert("Target URL updated successfully.");
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 text-white">
      <h2 className="text-4xl font-black tracking-tighter mb-10">Central Order Terminal</h2>
      <div className="space-y-6">
        {orders.map(o => (
          <div key={o.id} className="bg-[#0D0F18] p-10 rounded-[45px] border border-white/5 shadow-2xl space-y-8 animate-in fade-in duration-500">
             <div className="flex justify-between items-center">
               <div className="flex items-center gap-6">
                  <div className="p-5 bg-[#161924] rounded-[22px] text-purple-500 border border-white/5 shadow-inner">{PLATFORM_LOGOS[o.platform]}</div>
                  <div>
                    <h4 className="text-xl font-black tracking-tight">{o.service}</h4>
                    <p className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mt-1">QTY: {o.quantity.toLocaleString()} • User: {o.userId}</p>
                  </div>
               </div>
               <div className="text-right">
                  <p className="text-3xl font-black text-purple-500">₦{o.price.toLocaleString()}</p>
                  <span className="text-[10px] font-black text-gray-600 uppercase tracking-widest">{o.status}</span>
               </div>
             </div>
             <div className="bg-[#161924] p-6 rounded-[25px] flex items-center justify-between gap-6 border border-white/5">
                {editingId === o.id ? (
                  <input value={tempLink} onChange={e => setTempLink(e.target.value)} className="flex-1 bg-transparent border-none outline-none text-xs text-purple-400 font-mono" />
                ) : (
                  <p className="flex-1 text-xs text-gray-500 font-mono truncate select-all">{o.link}</p>
                )}
                <div className="flex gap-2">
                   <button onClick={() => {navigator.clipboard.writeText(o.link); alert("Link copied!");}} className="p-3 bg-white/5 rounded-xl hover:bg-white/10 transition-all"><ClipboardDocumentCheckIcon className="w-5 h-5 text-gray-400" /></button>
                   {editingId === o.id ? (
                     <button onClick={() => saveLink(o.id)} className="px-4 py-2 bg-green-600 rounded-xl text-[10px] font-black uppercase">SAVE</button>
                   ) : (
                     <button onClick={() => {setEditingId(o.id); setTempLink(o.link);}} className="p-3 bg-white/5 rounded-xl hover:bg-white/10 transition-all"><PencilSquareIcon className="w-5 h-5 text-gray-400" /></button>
                   )}
                </div>
             </div>
             <div className="flex flex-wrap gap-2 pt-6 border-t border-white/5">
                {[OrderStatus.PENDING, OrderStatus.PROCESSING, OrderStatus.CONFIRMED, OrderStatus.APPROVED, OrderStatus.COMPLETED].map(s => (
                  <button key={s} onClick={() => updateStatus(o.id, s)} className={`px-5 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${o.status === s ? 'bg-purple-600 text-white shadow-xl shadow-purple-900/10' : 'bg-white/5 text-gray-500 hover:text-white'}`}>
                    {s}
                  </button>
                ))}
             </div>
          </div>
        ))}
        {orders.length === 0 && <div className="text-center py-32 opacity-20 font-bold">No orders logged.</div>}
      </div>
    </div>
  );
};

// --- Page: Admin Dashboard Overview ---

const AdminDashboard = () => {
  const { users, orders, transactions } = useApp();
  const totalBalance = users.reduce((acc, u) => acc + u.balance, 0);
  const pendingPayments = transactions.filter(t => t.status === 'pending').length;

  return (
    <div className="space-y-12 text-white animate-in fade-in duration-700">
      <h2 className="text-4xl font-black tracking-tighter">Admin Terminal Overview</h2>
      <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-8">
        <div className="bg-[#0D0F18] p-10 rounded-[40px] border border-white/5 shadow-2xl">
           <UsersIcon className="w-10 h-10 text-blue-500 mb-4" />
           <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Total Agents</p>
           <p className="text-4xl font-black mt-1 tracking-tighter">{users.length}</p>
        </div>
        <div className="bg-[#0D0F18] p-10 rounded-[40px] border border-white/5 shadow-2xl">
           <AdjustmentsHorizontalIcon className="w-10 h-10 text-purple-500 mb-4" />
           <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Total Orders</p>
           <p className="text-4xl font-black mt-1 tracking-tighter">{orders.length}</p>
        </div>
        <div className="bg-[#0D0F18] p-10 rounded-[40px] border border-white/5 shadow-2xl">
           <BanknotesIcon className="w-10 h-10 text-green-500 mb-4" />
           <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Pending Verification</p>
           <p className="text-4xl font-black mt-1 tracking-tighter text-yellow-500">{pendingPayments}</p>
        </div>
        <div className="bg-[#0D0F18] p-10 rounded-[40px] border border-white/5 shadow-2xl">
           <WalletIcon className="w-10 h-10 text-purple-600 mb-4" />
           <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest">System Liability</p>
           <p className="text-4xl font-black mt-1 tracking-tighter">₦{totalBalance.toLocaleString()}</p>
        </div>
      </div>

      <div className="grid lg:grid-cols-2 gap-8">
         <div className="bg-[#0D0F18] rounded-[50px] p-12 border border-white/5 shadow-2xl">
            <h3 className="text-2xl font-black mb-8 tracking-tighter">Latest Transactions</h3>
            <div className="space-y-4">
               {transactions.slice(0, 5).map(t => (
                  <div key={t.id} className="p-6 bg-[#161924] rounded-[30px] flex items-center justify-between border border-white/5">
                     <div>
                        <p className="font-black text-green-500">₦{t.amount.toLocaleString()}</p>
                        <p className="text-[9px] text-gray-500 uppercase font-bold">{t.username} • {t.status}</p>
                     </div>
                     <Link to="/admin/payments" className="text-[10px] font-black text-purple-500 uppercase tracking-widest hover:underline">Verify</Link>
                  </div>
               ))}
               {transactions.length === 0 && <p className="text-center py-10 opacity-20">No transactions.</p>}
            </div>
         </div>
         <div className="bg-[#0D0F18] rounded-[50px] p-12 border border-white/5 shadow-2xl">
            <h3 className="text-2xl font-black mb-8 tracking-tighter">Recent System Orders</h3>
            <div className="space-y-4">
               {orders.slice(0, 5).map(o => (
                  <div key={o.id} className="p-6 bg-[#161924] rounded-[30px] flex items-center justify-between border border-white/5">
                     <div className="flex items-center gap-4">
                        <div className="text-purple-500">{PLATFORM_LOGOS[o.platform]}</div>
                        <div>
                           <p className="text-sm font-black">{o.service}</p>
                           <p className="text-[9px] text-gray-500 uppercase font-bold">{o.status}</p>
                        </div>
                     </div>
                     <Link to="/admin/orders" className="text-[10px] font-black text-purple-500 uppercase tracking-widest hover:underline">Manage</Link>
                  </div>
               ))}
               {orders.length === 0 && <p className="text-center py-10 opacity-20">No orders.</p>}
            </div>
         </div>
      </div>
    </div>
  );
};

export default function App() {
  return (
    <AppProvider>
      <Router>
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route path="/dashboard" element={<PrivateLayout><Dashboard /></PrivateLayout>} />
          <Route path="/new-order" element={<PrivateLayout><NewOrderPage /></PrivateLayout>} />
          <Route path="/congratulations" element={<PrivateLayout><OrderCongratulations /></PrivateLayout>} />
          <Route path="/orders" element={<PrivateLayout><OrdersHistoryPage /></PrivateLayout>} />
          <Route path="/wallet" element={<PrivateLayout><WalletPage /></PrivateLayout>} />
          <Route path="/affiliate" element={<PrivateLayout><AffiliatePage /></PrivateLayout>} />
          <Route path="/api-docs" element={<PrivateLayout><APIDocsPage /></PrivateLayout>} />
          <Route path="/support" element={<PrivateLayout><SupportPage /></PrivateLayout>} />
          <Route path="/admin/*" element={<PrivateLayout><Routes>
            <Route index element={<AdminDashboard />} />
            <Route path="users" element={<AdminUsersControl />} />
            <Route path="orders" element={<AdminOrdersControl />} />
            <Route path="payments" element={<AdminPaymentsControl />} />
          </Routes></PrivateLayout>} />
          <Route path="*" element={<Navigate to="/login" replace />} />
        </Routes>
      </Router>
    </AppProvider>
  );
}

