// --- Global State ---

interface AppContextType {
  user: User | null;
  setUser: (user: User | null) => void;
  users: User[];
  setUsers: React.Dispatch<React.SetStateAction<User[]>>;
  orders: Order[];
  setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
  tickets: Ticket[];
  setTickets: React.Dispatch<React.SetStateAction<Ticket[]>>;
  darkMode: boolean;
  setDarkMode: (dark: boolean) => void;
  isSidebarOpen: boolean;
  setIsSidebarOpen: (open: boolean) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

const ADMIN_CREDENTIALS = {
  email: 'johngideon179@gmail.com',
  password: 'Ellabike'
};

const generateID = (prefix: string) => `${prefix}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;

// --- App Provider ---

const AppProvider = ({ children }: { children?: React.ReactNode }) => {
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('user');
    return saved ? JSON.parse(saved) : null;
  });

  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('users');
    return saved ? JSON.parse(saved) : [];
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [tickets, setTickets] = useState<Ticket[]>(() => {
    const saved = localStorage.getItem('tickets');
    return saved ? JSON.parse(saved) : [];
  });

  const [darkMode, setDarkMode] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    if (user) {
      localStorage.setItem('user', JSON.stringify(user));
      setUsers(prev => {
        const idx = prev.findIndex(u => u.id === user.id);
        if (idx > -1) {
          const arr = [...prev];
          arr[idx] = user;
          return arr;
        }
        return [...prev, user];
      });
    } else {
      localStorage.removeItem('user');
    }
  }, [user]);

  useEffect(() => localStorage.setItem('users', JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem('orders', JSON.stringify(orders)), [orders]);
  useEffect(() => localStorage.setItem('transactions', JSON.stringify(transactions)), [transactions]);
  useEffect(() => localStorage.setItem('tickets', JSON.stringify(tickets)), [tickets]);

  useEffect(() => {
    if (darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [darkMode]);

  return (
    <AppContext.Provider value={{ 
      user, setUser, users, setUsers, orders, setOrders, transactions, setTransactions,
      tickets, setTickets, darkMode, setDarkMode, isSidebarOpen, setIsSidebarOpen
    }}>
      {children}
    </AppContext.Provider>
  );
};

// --- Authentication Flow ---

const LoginPage = () => {
  const { setUser, users, setUsers } = useApp();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [isLogin, setIsLogin] = useState(true);
  const [step, setStep] = useState<'info' | 'verify'>('info');

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();

    if (isLogin) {
      if (formData.email === ADMIN_CREDENTIALS.email && formData.password === ADMIN_CREDENTIALS.password) {
        const admin: User = {
          id: 'admin-001',
          username: 'John (Admin)',
          email: ADMIN_CREDENTIALS.email,
          role: 'admin',
          balance: 1000000,
          apiKey: 'ADMIN_API_KEY_SECURE',
          referralCode: 'ADMIN',
          referralEarnings: 0,
          createdAt: new Date().toISOString()
        };
        setUser(admin);
        navigate('/admin');
        return;
      }

      const foundUser = users.find(u => u.email === formData.email && u.password === formData.password);
      if (foundUser) {
        setUser(foundUser);
        navigate('/dashboard');
      } else {
        const exists = users.some(u => u.email === formData.email);
        if (!exists) {
          alert("CORRECTION: This email is not registered. Please sign up first to login!");
          setIsLogin(false);
        } else {
          alert("CORRECTION: Incorrect password. Please try again.");
        }
      }
    } else {
      if (step === 'info') {
        if (users.some(u => u.email === formData.email)) return alert("ERROR: Email already exists.");
        setStep('verify');
      } else {
        const newUser: User = {
          id: generateID('USR'),
          username: formData.email.split('@')[0],
          email: formData.email,
          password: formData.password,
          role: 'user',
          balance: 0,
          apiKey: generateID('KEY'),
          referralCode: generateID('REF'),
          referralEarnings: 0,
          createdAt: new Date().toISOString()
        };
        setUsers(prev => [...prev, newUser]);
        setUser(newUser);
        navigate('/dashboard');
      }
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#05060A] p-6 text-white font-['Inter']">
      <div className="max-w-md w-full bg-[#0D0F18] rounded-[40px] p-12 border border-white/5 shadow-2xl">
        <div className="text-center mb-10">
          <div className="w-16 h-16 bg-purple-600 rounded-2xl flex items-center justify-center text-white font-black text-3xl mx-auto mb-6">T</div>
          <h2 className="text-3xl font-black">{step === 'verify' ? 'Verification' : (isLogin ? 'Sign In' : 'Sign Up')}</h2>
        </div>
        <form onSubmit={handleAuth} className="space-y-4">
          {step === 'info' ? (
            <>
              <input required type="email" placeholder="Gmail Address" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-[#161924] border border-white/5 rounded-2xl px-6 py-5 outline-none focus:ring-2 focus:ring-purple-600 text-sm" />
              <input required type="password" placeholder="Password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full bg-[#161924] border border-white/5 rounded-2xl px-6 py-5 outline-none focus:ring-2 focus:ring-purple-600 text-sm" />
              <button type="submit" className="w-full py-5 bg-purple-600 rounded-2xl font-black text-lg">
                {isLogin ? 'Log In' : 'Continue'}
              </button>
            </>
          ) : (
            <div className="space-y-6">
              <p className="text-center text-xs text-gray-400">Code sent to <span className="text-purple-500 font-bold">{formData.email}</span>.</p>
              <input required type="text" maxLength={6} placeholder="000 000" className="w-full bg-[#161924] border-none rounded-2xl px-6 py-5 text-center text-2xl font-black outline-none focus:ring-2 focus:ring-purple-600" />
              <button type="submit" className="w-full py-5 bg-purple-600 rounded-2xl font-black text-lg">Verify</button>
            </div>
          )}
        </form>
        <button onClick={() => {setIsLogin(!isLogin); setStep('info');}} className="w-full mt-10 text-purple-500 font-black text-xs uppercase tracking-widest">
          {isLogin ? "Create your free account" : "Back to login"}
        </button>
      </div>
    </div>
  );
};

