const WalletPage = () => {
  const { user, transactions, setTransactions } = useApp();
  const [amt, setAmt] = useState(1000);
  const [receipt, setReceipt] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const accNo = "9067892034";

  const pendingTx = transactions.find(t => t.userId === user?.id && t.status === 'pending');

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setReceipt(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const notify = () => {
    if (!user) return;
    if (amt < 500) return alert("Minimum deposit is ₦500");
    if (!receipt) return alert("Please upload your payment screenshot first.");

    const tx: Transaction = { 
      id: generateID('TX'), 
      userId: user.id, 
      username: user.username, 
      amount: amt, 
      status: 'pending', 
      createdAt: new Date().toISOString(),
      receipt: receipt
    };
    setTransactions(prev => [tx, ...prev]);
    setReceipt(null);
    alert("Payment submitted! Admin will verify shortly.");
  };

  const copyAcc = () => {
    navigator.clipboard.writeText(accNo);
    alert("Account number copied!");
  };

  return (
    <div className="max-w-6xl mx-auto grid lg:grid-cols-5 gap-12 text-white animate-in fade-in duration-500">
       <div className="lg:col-span-3 space-y-8">
          <div className="bg-[#0D0F18] p-12 rounded-[50px] border border-white/5 shadow-2xl">
