            <div className="bg-purple-600 p-12 rounded-[45px] shadow-2xl shadow-purple-900/20 mb-12 relative overflow-hidden group">
               <p className="text-[10px] font-black uppercase opacity-60 mb-6 tracking-widest text-center">Transfer to OPay Bank</p>
               <div className="text-center space-y-4">
                  <div className="flex items-center justify-center gap-4">
                    <p className="text-5xl font-black tracking-tighter">{accNo}</p>
                    <button onClick={copyAcc} className="p-3 bg-white/10 rounded-2xl hover:bg-white/20 transition-all"><ClipboardIcon className="w-6 h-6" /></button>
                  </div>
                  <p className="text-lg font-bold uppercase tracking-widest opacity-80">John Gideon Ifebuche</p>
               </div>
            </div>

            {pendingTx ? (
              <div className="bg-yellow-500/10 border-2 border-yellow-500/20 p-10 rounded-[40px] text-center space-y-6 animate-pulse">
                <InformationCircleIcon className="w-16 h-16 text-yellow-500 mx-auto" />
