                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-500 uppercase ml-4 tracking-widest">Payment Proof</label>
                  <div onClick={() => fileInputRef.current?.click()} className="w-full h-48 bg-[#161924] rounded-[35px] border-2 border-dashed border-white/10 flex flex-col items-center justify-center cursor-pointer hover:border-purple-600/50 transition-all overflow-hidden">
