const NewOrderPage = () => {
  const { user, setUser, setOrders } = useApp();
  const navigate = useNavigate();
  const [platform, setPlatform] = useState<Platform>(Platform.FACEBOOK);
  const [catId, setCatId] = useState('');
  const [servId, setServId] = useState('');
  const [link, setLink] = useState('');
  const [quantity, setQuantity] = useState(100);
  const [autoRefill, setAutoRefill] = useState(true);

  const categories = PLATFORM_CATEGORIES[platform];
  const activeCategory = categories.find(c => c.id === catId) || categories[0];
  const activeService = activeCategory.services.find(s => s.id === servId) || activeCategory.services[0];

  const totalPrice = Math.round((quantity * activeService.pricePer1000) / 1000);
  const canAfford = (user?.balance || 0) >= totalPrice;

  const handleOrder = (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    if (quantity < activeService.min) return alert(`Minimum quantity: ${activeService.min}`);
    if (!canAfford) return alert("Wallet balance too low for this boost.");

    const newOrder: Order = {
      id: generateID('ORD'),
      userId: user.id,
      platform,
      service: activeService.name,
      link,
      quantity,
      price: totalPrice,
      status: OrderStatus.PENDING,
      createdAt: new Date().toISOString(),
      progress: 0,
      autoRefill: activeService.hasRefill ? autoRefill : false
    };

    setUser({...user, balance: user.balance - totalPrice});
    setOrders(prev => [newOrder, ...prev]);
    navigate('/congratulations', { state: { service: activeService.name } });
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 text-white">
      <div className="bg-[#0D0F18] rounded-[40px] p-10 border border-white/5 shadow-2xl">
        <div className="mb-10">
          <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-6 ml-2">1. Select Target Platform</p>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            {Object.values(Platform).map(p => (
              <button key={p} onClick={() => {setPlatform(p); setCatId(''); setServId('');}} className={`flex flex-col items-center justify-center gap-4 p-6 rounded-[30px] border-2 transition-all ${platform === p ? 'bg-purple-600 border-purple-500 text-white shadow-xl scale-[1.05]' : 'bg-[#161924] border-transparent text-gray-600 hover:text-white'}`}>
                {PLATFORM_LOGOS[p]}
                <span className="text-[10px] font-black uppercase">{p}</span>
              </button>
            ))}
          </div>
        </div>
        <div className="space-y-6">
          <div className="space-y-1.5">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-2">2. Category</p>
            <select value={catId} onChange={e => {setCatId(e.target.value); setServId('');}} className="w-full bg-[#161924] border-none rounded-[25px] px-8 py-5 text-sm font-black outline-none focus:ring-2 focus:ring-purple-600 appearance-none">
              {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="space-y-1.5">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-2">3. Package</p>
            <select value={servId} onChange={e => setServId(e.target.value)} className="w-full bg-[#161924] border-none rounded-[25px] px-8 py-5 text-sm font-black outline-none focus:ring-2 focus:ring-purple-600 appearance-none">
              {activeCategory.services.map(s => <option key={s.id} value={s.id}>{s.name} - ₦{s.pricePer1000}/1k</option>)}
            </select>
          </div>
          <div className="p-5 bg-white/5 rounded-3xl border border-white/5 flex gap-4 text-xs text-gray-400">
             <InformationCircleIcon className="w-5 h-5 text-purple-500 shrink-0" />
             {activeService.description}
          </div>
          <div className="space-y-1.5">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-2">4. Target Link</p>
            <input required type="url" value={link} onChange={e => setLink(e.target.value)} placeholder="https://..." className="w-full bg-[#161924] border-none rounded-[25px] px-8 py-5 text-sm font-black outline-none" />
          </div>
          <div className="space-y-1.5">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-2">5. Quantity (Min: {activeService.min})</p>
            <input required type="number" min={activeService.min} value={quantity} onChange={e => setQuantity(Number(e.target.value))} className="w-full bg-[#161924] border-none rounded-[25px] px-8 py-5 text-sm font-black outline-none" />
          </div>

          {activeService.hasRefill && (
            <div className="flex items-center justify-between p-6 bg-[#161924] rounded-[25px] border border-white/5">
              <div><p className="text-sm font-black">Auto-Refill Guarantee</p><p className="text-[10px] text-gray-500 uppercase font-bold">Automatic recovery on drops</p></div>
              <button type="button" onClick={() => setAutoRefill(!autoRefill)} className={`w-12 h-6 rounded-full transition-all relative ${autoRefill ? 'bg-purple-600' : 'bg-gray-700'}`}>
                <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${autoRefill ? 'left-7' : 'left-1'}`} />
              </button>
            </div>
          )}

          <div className="bg-purple-600/10 p-8 rounded-[35px] border border-purple-500/20 flex justify-between items-center">
            <p className="text-4xl font-black">₦{totalPrice.toLocaleString()}</p>
            {!canAfford && <span className="text-[8px] font-black text-red-500 uppercase bg-red-500/10 px-3 py-1 rounded-full">Insufficient Funds</span>}
          </div>
          <button onClick={handleOrder} className="w-full py-6 bg-purple-600 rounded-[30px] font-black text-xl hover:bg-purple-700 transition-all shadow-xl shadow-purple-900/20">Execute Growth Task</button>
        </div>
      </div>
    </div>
  );
};

